patch:
diff --git a/llvm/lib/Analysis/MemorySSAUpdater.cpp b/llvm/lib/Analysis/MemorySSAUpdater.cpp
index ecfecb03c375..96317be2789d 100644
--- a/llvm/lib/Analysis/MemorySSAUpdater.cpp
+++ b/llvm/lib/Analysis/MemorySSAUpdater.cpp
@@ -486,7 +486,7 @@ void MemorySSAUpdater::fixupDefs(const SmallVectorImpl<WeakVH> &Vars) {
     for (const auto *S : successors(NewDef->getBlock())) {
       if (auto *MP = MSSA->getMemoryAccess(S))
         setMemoryPhiValueForBlock(MP, NewDef->getBlock(), NewDef);
-      else
+      else if (MSSA->DT->dominates(NewDef->getBlock(), S))
         Worklist.push_back(S);
     }

@@ -501,6 +501,8 @@ void MemorySSAUpdater::fixupDefs(const SmallVectorImpl<WeakVH> &Vars) {
                "Should have already handled phi nodes!");
         // We are now this def's defining access, make sure we actually dominate
         // it
+        (void)NewDef;
+        (void)FirstDef;
         assert(MSSA->dominates(NewDef, FirstDef) &&
                "Should have dominated the new access");

@@ -521,7 +523,8 @@ void MemorySSAUpdater::fixupDefs(const SmallVectorImpl<WeakVH> &Vars) {
           // processed.  FIXME: Double check this
           if (!Seen.insert(S).second)
             continue;
-          Worklist.push_back(S);
+          if (MSSA->DT->dominates(NewDef->getBlock(), S))
+            Worklist.push_back(S);
         }
       }
     }

